exercises.solution_code:
#include <iostream>
#include <string>

struct Book
{
    std::string title;
    int year;
};

int main()
{
    std::string title1, title2;
    int year1, year2;

    std::cin >> title1 >> year1 >> title2 >> year2;

    Book b1 { title1, year1 };
    Book b2 { title2, year2 };

    auto [t1, y1] = b1;
    std::cout << '"' << t1 << '"' << " published in " << y1 << '\n';

    auto [t2, y2] = b2;
    std::cout << '"' << t2 << '"' << " published in " << y2 << '\n';

    return 0;
}

