exercises.solution_code:
#include <iostream>
#include <string>

enum Category
{
    Electronics = 0,
    Clothing    = 1,
    Food        = 2
};

struct Product
{
    std::string name;
    Category    category;
};

std::string categoryName(Category c)
{
    switch (c)
    {
        case Electronics: return "Electronics";
        case Clothing:    return "Clothing";
        case Food:        return "Food";
        default:          return "Unknown";
    }
}

int main()
{
    Product catalog[3];

    for (int i = 0; i < 3; ++i)
    {
        std::string name;
        int code;
        std::cin >> name >> code;
        catalog[i] = Product{ name, static_cast<Category>(code) };
    }

    for (int i = 0; i < 3; ++i)
    {
        auto [n, c] = catalog[i];
        std::cout << n << ": " << categoryName(c) << '\n';
    }

    return 0;
}
